排序后逐个匹配，x % 10^len 取末len位。

```cpp
#include <bits/stdc++.h>
using namespace std;
int main() {
    int n, q; cin >> n >> q;
    vector<int> a(n);
    for (int i = 0; i < n; i++) cin >> a[i];
    sort(a.begin(), a.end());
    while (q--) {
        int len, code; cin >> len >> code;
        int mod = 1;
        for (int i = 0; i < len; i++) mod *= 10;
        int ans = -1;
        for (int x : a)
            if (x % mod == code) { ans = x; break; }
        cout << ans << endl;
    }
    return 0;
}
```

枚举年份构造回文日期，检查合法性及范围。

```cpp
#include <bits/stdc++.h>
using namespace std;
int days[13]={0,31,28,31,30,31,30,31,31,30,31,30,31};
bool isLeap(int y){return(y%4==0&&y%100!=0)||y%400==0;}
int main(){
    int s,e;cin>>s>>e;
    int ans=0;
    for(int y=s/10000;y<=e/10000;y++){
        int m=(y%10)*10+(y/10)%10;
        int d=((y/100)%10)*10+y/1000;
        if(m<1||m>12)continue;
        int lim=days[m];
        if(m==2&&isLeap(y))lim=29;
        if(d<1||d>lim)continue;
        int date=y*10000+m*100+d;
        if(date>=s&&date<=e)ans++;
    }
    cout<<ans<<endl;return 0;
}
```

桶计数，成绩0~600。

```cpp
#include <bits/stdc++.h>
using namespace std;
int cnt[601];
int main(){
    int n,w;cin>>n>>w;
    for(int i=1;i<=n;i++){
        int x;cin>>x;cnt[x]++;
        int win=max(1,i*w/100);
        int sum=0;
        for(int s=600;s>=0;s--){
            sum+=cnt[s];
            if(sum>=win){cout<<s<<" ";break;}
        }
    }
    return 0;
}
```

队列存券，公交遍历找可用券。

```cpp
#include <bits/stdc++.h>
using namespace std;
struct Tic{int p,t;};
int main(){
    int n;cin>>n;
    queue<Tic> q;
    int ans=0;
    while(n--){
        int tp,pr,ti;cin>>tp>>pr>>ti;
        while(!q.empty()&&ti-q.front().t>45)q.pop();
        if(tp==0){q.push({pr,ti});ans+=pr;}
        else{
            bool u=0;int sz=q.size();
            for(int i=0;i<sz;i++){
                Tic t=q.front();q.pop();
                if(!u&&t.p>=pr){u=1;continue;}
                q.push(t);
            }
            if(!u)ans+=pr;
        }
    }
    cout<<ans<<endl;return 0;
}
```
